struct Session: Codable {
    let accessToken: String
    let refreshToken: String
    let expiresAt: Date
}

final class AuthManager: ObservableObject {
    static let shared = AuthManager()

    @Published private(set) var session: Session?
    @Published private(set) var isAuthenticated: Bool = false

    private let service = "com.yourcompany.tradingapp"
    private let account = "session"

    private init() {
        loadSession()
    }

    func loadSession() {
        do {
            let data = try KeychainStore.shared.get(service: service, account: account)
            let decoded = try JSONDecoder.trading.decode(Session.self, from: data)
            self.session = decoded
            self.isAuthenticated = decoded.expiresAt > Date()
        } catch {
            self.session = nil
            self.isAuthenticated = false
        }
    }

    func saveSession(_ session: Session) {
        do {
            let data = try JSONEncoder.trading.encode(session)
            try KeychainStore.shared.set(data, service: service, account: account)
            self.session = session
            self.isAuthenticated = session.expiresAt > Date()
        } catch {
            self.session = nil
            self.isAuthenticated = false
        }
    }

    func clearSession() {
        KeychainStore.shared.delete(service: service, account: account)
        session = nil
        isAuthenticated = false
    }

    func validAccessToken() -> String? {
        guard let s = session, s.expiresAt > Date().addingTimeInterval(30) else { return nil }
        return s.accessToken
    }
}

