enum APIError: Error, LocalizedError {
    case invalidResponse
    case http(Int, String?)
    case decoding
    case unauthorized
    case transport(String)

    var errorDescription: String? {
        switch self {
        case .invalidResponse: return "Invalid server response."
        case .http(let code, let msg): return "Server error (\(code)) \(msg ?? "")"
        case .decoding: return "Failed to decode server response."
        case .unauthorized: return "Session expired. Please sign in again."
        case .transport(let msg): return msg
        }
    }
}

struct EmptyResponse: Codable {}

final class APIClient {
    static let shared = APIClient()

    private let env = Environment.shared
    private let auth = AuthManager.shared

    private lazy var session: URLSession = {
        let cfg = URLSessionConfiguration.ephemeral
        cfg.timeoutIntervalForRequest = 20
        cfg.waitsForConnectivity = true
        cfg.httpMaximumConnectionsPerHost = 6
        return URLSession(configuration: cfg)
    }()

    private init() {}

    func request<T: Decodable>(
        _ method: String,
        path: String,
        body: Encodable? = nil,
        query: [URLQueryItem] = [],
        requiresAuth: Bool = true
    ) async throws -> T {
        var url = env.config.baseURL.appendingPathComponent(path)
        if !query.isEmpty {
            var comps = URLComponents(url: url, resolvingAgainstBaseURL: false)!
            comps.queryItems = query
            url = comps.url!
        }

        var req = URLRequest(url: url)
        req.httpMethod = method
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        req.setValue("application/json", forHTTPHeaderField: "Accept")
        req.setValue(env.config.apiKey, forHTTPHeaderField: "X-API-Key")
        req.setValue(env.config.appVersion, forHTTPHeaderField: "X-App-Version")
        req.setValue(env.config.deviceId, forHTTPHeaderField: "X-Device-Id")
        req.setValue(Self.userAgent(), forHTTPHeaderField: "User-Agent")
        req.cachePolicy = .reloadIgnoringLocalCacheData

        if requiresAuth {
            guard let token = auth.validAccessToken() else { throw APIError.unauthorized }
            req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        if let body {
            let data = try JSONEncoder.trading.encode(AnyEncodable(body))
            req.httpBody = data
            let sig = Self.hmacSHA256(data: data, key: env.config.apiKey)
            req.setValue(sig, forHTTPHeaderField: "X-Body-Signature")
        } else {
            req.setValue(Self.hmacSHA256(data: Data(), key: env.config.apiKey), forHTTPHeaderField: "X-Body-Signature")
        }

        do {
            let (data, resp) = try await session.data(for: req)
            guard let http = resp as? HTTPURLResponse else { throw APIError.invalidResponse }
            if http.statusCode == 401 { throw APIError.unauthorized }
            guard (200...299).contains(http.statusCode) else {
                let msg = String(data: data, encoding: .utf8)
                throw APIError.http(http.statusCode, msg)
            }
            if T.self == EmptyResponse.self {
                return EmptyResponse() as! T
            }
            do {
                return try JSONDecoder.trading.decode(T.self, from: data)
            } catch {
                throw APIError.decoding
            }
        } catch let e as APIError {
            throw e
        } catch {
            throw APIError.transport(error.localizedDescription)
        }
    }

    private static func userAgent() -> String {
        let app = Bundle.main.infoDictionary?["CFBundleName"] as? String ?? "TradingApp"
        let ver = Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        let os = UIDevice.current.systemVersion
        let model = UIDevice.current.model
        return "\(app)/\(ver) (iOS \(os); \(model))"
    }

    private static func hmacSHA256(data: Data, key: String) -> String {
        let keyData = Data(key.utf8)
        let symmetricKey = SymmetricKey(data: keyData)
        let mac = HMAC<SHA256>.authenticationCode(for: data, using: symmetricKey)
        return Data(mac).base64EncodedString()
    }
}

struct AnyEncodable: Encodable {
    private let encodeFunc: (Encoder) throws -> Void
    init(_ encodable: Encodable) { self.encodeFunc = encodable.encode }
    func encode(to encoder: Encoder) throws { try encodeFunc(encoder) }
}

