// MARK: - WebSocket Quote Stream

final class QuoteStream: ObservableObject {
    @Published private(set) var quotes: [String: StockQuote] = [:]
    @Published private(set) var isConnected: Bool = false
    @Published private(set) var lastError: String?

    private let env = Environment.shared
    private let auth = AuthManager.shared

    private var task: URLSessionWebSocketTask?
    private var cancellables = Set<AnyCancellable>()
    private var reconnectTask: Task<Void, Never>?
    private var symbols = Set<String>()
    private var pingTimer: Timer?

    init() {
        auth.$isAuthenticated
            .sink { [weak self] authed in
                guard let self else { return }
                if authed {
                    self.connectIfNeeded()
                } else {
                    self.disconnect()
                }
            }
            .store(in: &cancellables)
    }

    func subscribe(_ symbol: String) {
        symbols.insert(symbol.uppercased())
        sendSubscription()
    }

    func unsubscribe(_ symbol: String) {
        symbols.remove(symbol.uppercased())
        sendSubscription()
    }

    func connectIfNeeded() {
        guard task == nil else { return }
        guard let token = auth.validAccessToken() else { return }
        var req = URLRequest(url: env.config.wsURL)
        req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        req.setValue(env.config.apiKey, forHTTPHeaderField: "X-API-Key")
        req.setValue(env.config.deviceId, forHTTPHeaderField: "X-Device-Id")

        let cfg = URLSessionConfiguration.ephemeral
        cfg.waitsForConnectivity = true
        let session = URLSession(configuration: cfg)
        let wsTask = session.webSocketTask(with: req)
        self.task = wsTask
        wsTask.resume()
        isConnected = true
        lastError = nil

        startReceiveLoop()
        startPing()
        sendSubscription()
    }

    func disconnect() {
        pingTimer?.invalidate()
        pingTimer = nil
        reconnectTask?.cancel()
        reconnectTask = nil
        isConnected = false
        task?.cancel(with: .goingAway, reason: nil)
        task = nil
    }

    private func startPing() {
        pingTimer?.invalidate()
        pingTimer = Timer.scheduledTimer(withTimeInterval: 15, repeats: true) { [weak self] _ in
            self?.task?.sendPing { err in
                if let err {
                    DispatchQueue.main.async {
                        self?.lastError = err.localizedDescription
                        self?.scheduleReconnect()
                    }
                }
            }
        }
    }

    private func startReceiveLoop() {
        guard let task else { return }
        task.receive { [weak self] result in
            guard let self else { return }
            switch result {
            case .failure(let err):
                DispatchQueue.main.async {
                    self.lastError = err.localizedDescription
                    self.isConnected = false
                    self.scheduleReconnect()
                }
            case .success(let msg):
                self.handleMessage(msg)
                self.startReceiveLoop()
            }
        }
    }

    private func handleMessage(_ msg: URLSessionWebSocketTask.Message) {
        let data: Data?
        switch msg {
        case .data(let d): data = d
        case .string(let s): data = s.data(using: .utf8)
        @unknown default: data = nil
        }
        guard let data else { return }
        if let quote = try? JSONDecoder.trading.decode(StockQuote.self, from: data) {
            DispatchQueue.main.async {
                self.quotes[quote.symbol.uppercased()] = quote
            }
        } else if let batch = try? JSONDecoder.trading.decode([StockQuote].self, from: data) {
            DispatchQueue.main.async {
                for q in batch { self.quotes[q.symbol.uppercased()] = q }
            }
        }
    }

    private func sendSubscription() {
        guard let task else { return }
        let payload: [String: Any] = [
            "type": "subscribe",
            "symbols": Array(symbols).sorted()
        ]
        if let data = try? JSONSerialization.data(withJSONObject: payload),
           let str = String(data: data, encoding: .utf8) {
            task.send(.string(str)) { [weak self] err in
                if let err {
                    DispatchQueue.main.async {
                        self?.lastError = err.localizedDescription
                        self?.scheduleReconnect()
                    }
                }
            }
        }
    }

    private func scheduleReconnect() {
        guard reconnectTask == nil else { return }
        disconnect()
        reconnectTask = Task { [weak self] in
            guard let self else { return }
            var backoff: UInt64 = 700_000_000
            for _ in 0..<8 {
                if Task.isCancelled { return }
                try? await Task.sleep(nanoseconds: backoff)
                await MainActor.run { self.connectIfNeeded() }
                if self.isConnected {
                    self.reconnectTask = nil
                    return
                }
                backoff = min(backoff * 2, 10_000_000_000)
            }
            await MainActor.run { self.reconnectTask = nil }
        }
    }
}

// MARK: - Local Portfolio Store

final class PortfolioStore: ObservableObject {
    @Published private(set) var portfolio: Portfolio = Portfolio(cash: 0, positions: [])
    @Published private(set) var executions: [TradeExecution] = []
    @Published var isLoading: Bool = false
    @Published var lastError: String?

    private let api = TradingAPI.shared
    private let stream: QuoteStream
    private var cancellables = Set<AnyCancellable>()

    init(stream: QuoteStream) {
        self.stream = stream
        stream.$quotes
            .receive(on: DispatchQueue.main)
            .sink { [weak self] quotes in
                self?.applyQuotes(quotes)
            }
            .store(in: &cancellables)
    }

    @MainActor
    func refresh() async {
        isLoading = true
        lastError = nil
        do {
            let p = try await api.fetchPortfolio()
            portfolio = p
            for pos in p.positions { stream.subscribe(pos.symbol) }
            executions = try await api.fetchRecentExecutions()
        } catch {
            lastError = (error as? LocalizedError)?.errorDescription ?? error.localizedDescription
        }
        isLoading = false
    }

    private func applyQuotes(_ quotes: [String: StockQuote]) {
        guard !portfolio.positions.isEmpty else { return }
        var updated = portfolio
        var changed = false
        for i in updated.positions.indices {
            let sym = updated.positions[i].symbol.uppercased()
            if let q = quotes[sym] {
                let newPrice = q.last
                if updated.positions[i].marketPrice != newPrice {
                    updated.positions[i].marketPrice = newPrice
                    changed = true
                }
            }
        }
        if changed { portfolio = updated }
    }

    @MainActor
    func recordExecution(_ exec: TradeExecution) {
        executions.insert(exec, at: 0)
        executions = Array(executions.prefix(100))
    }
}

// MARK: - Trade Engine (Client-side checks + submit + optimistic UX)

enum TradeValidationError: Error, LocalizedError {
    case invalidSymbol
    case invalidQuantity
    case invalidLimitPrice
    case insufficientFunds

    var errorDescription: String? {
        switch self {
        case .invalidSymbol: return "Enter a valid symbol."
        case .invalidQuantity: return "Enter a valid quantity."
        case .invalidLimitPrice: return "Enter a valid limit price."
        case .insufficientFunds: return "Insufficient buying power."
        }
    }
}

final class TradeEngine: ObservableObject {
    @Published var isSubmitting: Bool = false
    @Published var lastError: String?
    @Published var lastAck: OrderAck?

    private let api = TradingAPI.shared
    private let stream: QuoteStream
    private let store: PortfolioStore

    init(stream: QuoteStream, store: PortfolioStore) {
        self.stream = stream
        self.store = store
    }

    func validate(symbol: String, side: OrderSide, type: OrderType, quantityText: String, limitPriceText: String?) throws -> (String, Double, Double?) {
        let sym = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard sym.range(of: #"^[A-Z0-9\.\-]{1,10}$"#, options: .regularExpression) != nil else {
            throw TradeValidationError.invalidSymbol
        }
        let qty = Double(quantityText.trimmingCharacters(in: .whitespacesAndNewlines)) ?? 0
        guard qty > 0 else { throw TradeValidationError.invalidQuantity }

        var limit: Double? = nil
        if type == .limit {
            let lp = Double((limitPriceText ?? "").trimmingCharacters(in: .whitespacesAndNewlines)) ?? 0
            guard lp > 0 else { throw TradeValidationError.invalidLimitPrice }
            limit = lp
        }

        if side == .buy {
            let estPrice: Double
            if type == .market {
                estPrice = stream.quotes[sym]?.ask ?? stream.quotes[sym]?.last ?? 0
            } else {
                estPrice = limit ?? 0
            }
            if estPrice > 0 {
                let estCost = estPrice * qty
                if store.portfolio.cash < estCost {
                    throw TradeValidationError.insufficientFunds
                }
            }
        }
        return (sym, qty, limit)
    }

    @MainActor
    func submit(symbol: String, side: OrderSide, type: OrderType, quantityText: String, limitPriceText: String?) async {
        isSubmitting = true
        lastError = nil
        lastAck = nil
        do {
            let (sym, qty, limit) = try validate(symbol: symbol, side: side, type: type, quantityText: quantityText, limitPriceText: limitPriceText)
            stream.subscribe(sym)
            let order = TradeOrder(
                id: UUID().uuidString,
                symbol: sym,
                side: side,
                type: type,
                quantity: qty,
                limitPrice: limit,
                clientTs: Date()
            )
            let ack = try await api.submitOrder(order)
            lastAck = ack
            await store.refresh()
        } catch {
            lastError = (error as? LocalizedError)?.errorDescription ?? error.localizedDescription
        }
        isSubmitting = false
    }
}

