    @State private var symbol = "AAPL"
    @State private var side: OrderSide = .buy
    @State private var type: OrderType = .market
    @State private var quantity = "1"
    @State private var limitPrice = ""
    @State private var showConfirm = false

    var quote: StockQuote? { stream.quotes[symbol.uppercased()] }

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 14) {
                    VStack(spacing: 10) {
                        HStack {
                            TextField("Symbol", text: $symbol)
                                .textInputAutocapitalization(.characters)
                                .autocorrectionDisabled()
                                .onChange(of: symbol) { _, newValue in
                                    let sym = newValue.uppercased()
                                    if sym.count <= 10 {
                                        stream.subscribe(sym)
                                    }
                                }
                                .padding(12)
                                .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 12))

                            Button {
                                stream.subscribe(symbol.uppercased())
                            } label: {
                                Image(systemName: "bolt.horizontal.circle")
                                    .font(.title3)
                            }
                            .buttonStyle(.bordered)
                        }

                        QuoteCardView(symbol: symbol.uppercased(), quote: quote)
                    }

                    VStack(spacing: 12) {
                        Picker("Side", selection: $side) {
                            Text("Buy").tag(OrderSide.buy)
                            Text("Sell").tag(OrderSide.sell)
                        }
                        .pickerStyle(.segmented)

                        Picker("Type", selection: $type) {
                            Text("Market").tag(OrderType.market)
                            Text("Limit").tag(OrderType.limit)
                        }
                        .pickerStyle(.segmented)

                        HStack(spacing: 12) {
                            LabeledField(title: "Qty", text: $quantity, keyboard: .decimalPad)
                            if type == .limit {
                                LabeledField(title: "Limit", text: $limitPrice, keyboard: .decimalPad)
                            }
                        }

                        HStack {
                            VStack(alignment: .leading, spacing: 4) {
                                Text("Buying Power").font(.footnote).foregroundStyle(.secondary)
                                Text(store.portfolio.cash.asCurrency()).font(.headline)
                            }
                            Spacer()
                            VStack(alignment: .trailing, spacing: 4) {
                                Text("Equity").font(.footnote).foregroundStyle(.secondary)
                                Text(store.portfolio.equity.asCurrency()).font(.headline)
                            }
                        }
                        .padding(12)
                        .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 12))
                    }

                    VStack(spacing: 10) {
                        if let err = engine.lastError {
                            BannerView(text: err, style: .error)
                        } else if let ack = engine.lastAck {
                            BannerView(text: ack.message ?? "Order \(ack.status.rawValue). ID: \(ack.orderId)", style: ack.status == .filled ? .success : .info)
                        }

                        Button {
                            showConfirm = true
                        } label: {
                            HStack {
                                if engine.isSubmitting { ProgressView().tint(.white) }
                                Text(engine.isSubmitting ? "Submitting..." : "Review Order")
                                    .fontWeight(.semibold)
                            }
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 14)
                        }
                        .buttonStyle(.borderedProminent)
                        .disabled(engine.isSubmitting)
                    }
                }
                .padding(16)
            }
            .navigationTitle("Trade")
            .refreshable { await store.refresh() }
            .sheet(isPresented: $showConfirm) {
                ConfirmOrderSheet(
                    symbol: symbol.uppercased(),
                    side: side,
                    type: type,
                    quantityText: quantity,
                    limitPriceText: type == .limit ? limitPrice : nil,
                    quote: quote,
                    buyingPower: store.portfolio.cash,
                    onSubmit: {
                        showConfirm = false
                        Task { await engine.submit(symbol: symbol, side: side, type: type, quantityText: quantity, limitPriceText: type == .limit ? limitPrice : nil) }
                    }
                )
                .presentationDetents([.medium, .large])
            }
        }
    }
}

struct ConfirmOrderSheet: View {
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantityText: String
    let limitPriceText: String?
    let quote: StockQuote?
    let buyingPower: Double
    let onSubmit: () -> Void

    @Environment(\.dismiss) private var dismiss
    @State private var validationError: String?

    var body: some View {
        NavigationStack {
            VStack(spacing: 12) {
                VStack(alignment: .leading, spacing: 6) {
                    Text("Review Order").font(.title2.bold())
                    Text("Confirm details before submitting.").foregroundStyle(.secondary)
                }
                .frame(maxWidth: .infinity, alignment: .leading)

                VStack(spacing: 10) {
                    row("Symbol", symbol)
                    row("Side", side.rawValue.capitalized)
                    row("Type", type.rawValue.capitalized)
                    row("Quantity", quantityText)
                    if type == .limit { row("Limit Price", (Double(limitPriceText ?? "") ?? 0).asCurrency()) }
                    if let quote {
                        row("Bid / Ask", "\(quote.bid.asCurrency()) / \(quote.ask.asCurrency())")
                        row("Last", quote.last.asCurrency())
                    } else {
                        row("Quote", "Loading...")
                    }

                    Divider()

                    let qty = Double(quantityText) ?? 0
                    let estPrice = (type == .limit ? Double(limitPriceText ?? "") : nil) ?? quote?.ask ?? quote?.last ?? 0
                    let estNotional = max(0, qty * estPrice)

                    row("Estimated Notional", estNotional.asCurrency())
                    row("Buying Power", buyingPower.asCurrency())
                }
                .padding(12)
                .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 12))

                if let validationError {
                    BannerView(text: validationError, style: .error)
                }

                HStack(spacing: 10) {
                    Button("Cancel") { dismiss() }
                        .buttonStyle(.bordered)
                        .frame(maxWidth: .infinity)

                    Button("Submit") {
                        validateAndSubmit()
                    }
                    .buttonStyle(.borderedProminent)
                    .frame(maxWidth: .infinity)
                }

                Spacer()
            }
            .padding(16)
            .navigationBarTitleDisplayMode(.inline)
        }
    }

    private func row(_ title: String, _ value: String) -> some View {
        HStack {
            Text(title).foregroundStyle(.secondary)
            Spacer()
            Text(value).fontWeight(.semibold)
        }
        .font(.subheadline)
    }

    private func validateAndSubmit() {
        validationError = nil
        let qty = Double(quantityText) ?? 0
        if qty <= 0 { validationError = "Invalid quantity."; return }
        if type == .limit {
            let lp = Double(limitPriceText ?? "") ?? 0
            if lp <= 0 { validationError = "Invalid limit price."; return }
        }
        onSubmit()
    }
}

struct QuoteCardView: View {
    let symbol: String
    let quote: StockQuote?

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(alignment: .firstTextBaseline) {
                Text(symbol).font(.title2.bold())
                Spacer()
                if let quote {
                    let isUp = quote.change >= 0
                    Text("\(quote.change >= 0 ? "+" : "")\(quote.change.asCurrency()) (\(quote.changePct.asPercent()))")
                        .font(.subheadline.weight(.semibold))
                        .foregroundStyle(isUp ? .green : .red)
                } else {
                    Text("—").foregroundStyle(.secondary)
                }
            }
            HStack {
                stat("Bid", quote?.bid.asCurrency() ?? "—")
                Spacer()
                stat("Ask", quote?.ask.asCurrency() ?? "—")
                Spacer()
                stat("Last", quote?.last.asCurrency() ?? "—")
            }
        }
        .padding(14)
        .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 16))
    }

    private func stat(_ title: String, _ value: String) -> some View {
        VStack(alignment: .leading, spacing: 2) {
            Text(title).font(.footnote).foregroundStyle(.secondary)
            Text(value).font(.headline)
        }
    }
}

