struct PositionDetailView: View {
    let symbol: String
    @ObservedObject var stream: QuoteStream
    @State private var quote: StockQuote?
    @State private var error: String?

    var body: some View {
        VStack(spacing: 14) {
            QuoteCardView(symbol: symbol, quote: quote ?? stream.quotes[symbol])
            if let error { BannerView(text: error, style: .error) }
            Spacer()
        }
        .padding(16)
        .navigationTitle(symbol)
        .task {
            stream.subscribe(symbol)
            do {
                quote = try await TradingAPI.shared.fetchQuote(symbol: symbol)
            } catch {
                self.error = (error as? LocalizedError)?.errorDescription ?? error.localizedDescription
            }
        }
    }
