// MARK: - Formatting Helpers

extension Double {
    func asCurrency(code: String = "USD") -> String {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.currencyCode = code
        f.maximumFractionDigits = 2
        f.minimumFractionDigits = 2
        return f.string(from: NSNumber(value: self)) ?? "\(self)"
    }

    func asPercent() -> String {
        let f = NumberFormatter()
        f.numberStyle = .percent
        f.maximumFractionDigits = 2
        f.minimumFractionDigits = 2
        return f.string(from: NSNumber(value: self / 100.0)) ?? "\(self)%"
    }

    func cleanQty() -> String {
        if self.rounded() == self { return String(format: "%.0f", self) }
        return String(format: "%.4f", self).replacingOccurrences(of: #"0+$"#, with: "", options: .regularExpression)
            .replacingOccurrences(of: #"\.$"#, with: "", options: .regularExpression)
    }
}

